def matmul(A: list[list[float]], B: list[list[float]]) -> list[list[float]]:
    m = len(A)
    n = len(A[0])
    n2 = len(B)
    p = len(B[0])

    if n != n2:
        raise ValueError(f"Cannot multiply: A has {n} cols but B has {n2} rows")

    C = [[0.0] * p for _ in range(m)]

    for i in range(m):
        for j in range(p):
            for k in range(n):
                C[i][j] += A[i][k] * B[k][j]

    return C

